const listPenaltyStatusHistory = `-- name: ListPenaltyStatusHistory :many
SELECT id, penalty_id, from_status, to_status,
       transitioned_by_user_id, transitioned_at, notes,
       status, created_at, updated_at,
       created_by, updated_by
  FROM penalty_status_history
 WHERE penalty_id = $1
 ORDER BY transitioned_at DESC
`

func (q *Queries) ListPenaltyStatusHistory(ctx context.Context, penaltyID pgtype.UUID) ([]PenaltyStatusHistory, error) {
	rows, err := q.db.Query(ctx, listPenaltyStatusHistory, penaltyID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []PenaltyStatusHistory
	for rows.Next() {
		var i PenaltyStatusHistory
		if err := rows.Scan(
			&i.ID, &i.PenaltyID, &i.FromStatus, &i.ToStatus,
			&i.TransitionedByUserID, &i.TransitionedAt, &i.Notes,
			&i.Status, &i.CreatedAt, &i.UpdatedAt,
			&i.CreatedBy, &i.UpdatedBy,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

