const lockPendingPenaltyOutboxEvents = `-- name: LockPendingPenaltyOutboxEvents :many
SELECT id, penalty_id, event_type, payload, idempotency_key,
       created_at, next_attempt_at, attempts,
       delivered_at, last_error
  FROM penalty_outbox_events
 WHERE delivered_at IS NULL
   AND next_attempt_at <= now()
 ORDER BY next_attempt_at ASC
 LIMIT $1
 FOR UPDATE SKIP LOCKED
`

func (q *Queries) LockPendingPenaltyOutboxEvents(ctx context.Context, limit int32) ([]PenaltyOutboxEvent, error) {
	rows, err := q.db.Query(ctx, lockPendingPenaltyOutboxEvents, limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []PenaltyOutboxEvent
	for rows.Next() {
		var i PenaltyOutboxEvent
		if err := rows.Scan(
			&i.ID, &i.PenaltyID, &i.EventType, &i.Payload, &i.IdempotencyKey,
			&i.CreatedAt, &i.NextAttemptAt, &i.Attempts,
			&i.DeliveredAt, &i.LastError,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

